Here's a solid pattern using `MockHttpMessageHandler` and MSTest's async support:

```csharp
[TestClass]
public class DataFetcherTests
{
    private static HttpClient CreateClient(HttpStatusCode status, string content = "")
    {
        var handler = new MockHandler(new HttpResponseMessage(status)
        {
            Content = new StringContent(content)
        });
        return new HttpClient(handler);
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        using var client = CreateClient(HttpStatusCode.OK, "hello");
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnServerError()
    {
        using var client = CreateClient(HttpStatusCode.InternalServerError);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenCancelled()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        using var client = CreateClient(HttpStatusCode.OK, "data");
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnTimeout()
    {
        // Handler that delays longer than the timeout
        var handler = new DelayHandler(TimeSpan.FromSeconds(30));
        using var client = new HttpClient(handler) { Timeout = TimeSpan.FromMilliseconds(50) };
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // --- Test helpers ---

    private class MockHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage _response;
        public MockHandler(HttpResponseMessage response) => _response = response;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(_response);
        }
    }

    private class DelayHandler : HttpMessageHandler
    {
        private readonly TimeSpan _delay;
        public DelayHandler(TimeSpan delay) => _delay = delay;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            await Task.Delay(_delay, cancellationToken);
            return new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key points:**

- **Custom `HttpMessageHandler`** — avoids mocking frameworks; gives full control over `SendAsync`
- **Cancellation test** — pre-cancel the token; `ThrowIfCancellationRequested` in the handler makes `GetAsync` throw `TaskCanceledException`
- **Timeout test** — set `HttpClient.Timeout` low and make the handler delay; `HttpClient` internally cancels, producing `TaskCanceledException`
- **Always `async Task`** — MSTest natively awaits async test methods; never use `async void`
- You can also set `[Timeout(5000)]` on any test method as a safety net against hangs
